import{_ as a,o,c as t,a2 as l}from"./chunks/framework.D5wUhsuj.js";const m=JSON.parse('{"title":"Development Setup","description":"","frontmatter":{},"headers":[],"relativePath":"development/01-development-setup.md","filePath":"development/01-development-setup.md"}'),i={name:"development/01-development-setup.md"};function n(p,e,d,r,s,c){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="development-setup" tabindex="-1">Development Setup <a class="header-anchor" href="#development-setup" aria-label="Permalink to &quot;Development Setup&quot;">​</a></h1><h2 id="ucel" tabindex="-1">Účel <a class="header-anchor" href="#ucel" aria-label="Permalink to &quot;Účel&quot;">​</a></h2><p>Tento dokument popisuje kompletní zprovoznění vývojového prostředí od čistého zařízení až po první úspěšný build aplikace (React frontend + Capacitor Android).</p><h2 id="cilova-platforma" tabindex="-1">Cílová platforma <a class="header-anchor" href="#cilova-platforma" aria-label="Permalink to &quot;Cílová platforma&quot;">​</a></h2><p>Primární vývoj probíhá přímo na mobilním zařízení (Motorola / Android).</p><p>Používané prostředí:</p><ul><li>Termux</li><li>Ubuntu (proot-distro)</li><li>Git</li><li>Node.js &amp; npm (pro React a Vite)</li><li>Java JDK 21</li><li>Android SDK</li><li>Gradle</li><li>Capacitor</li></ul><h2 id="doporuceny-postup" tabindex="-1">Doporučený postup <a class="header-anchor" href="#doporuceny-postup" aria-label="Permalink to &quot;Doporučený postup&quot;">​</a></h2><ol><li>Aktualizovat Termux a nainstalovat Ubuntu (proot).</li><li>Nainstalovat Git, Node.js a JDK 21.</li><li>Nainstalovat a nastavit Android SDK.</li><li>Naklonovat repozitář: <code>git clone ...</code></li><li>Nainstalovat NPM závislosti: <code>npm install</code></li><li>Nastavit API endpointy (ověřit, že aplikace míří na AWS backend <code>13.49.77.58</code> nebo lokální IP).</li><li>Sestavit webovou část: <code>npm run build</code></li><li>Synchronizovat Capacitor: <code>npx cap sync android</code></li><li>Sestavit Android APK: <code>cd android &amp;&amp; ./gradlew assembleDebug</code></li></ol><h2 id="vysledek" tabindex="-1">Výsledek <a class="header-anchor" href="#vysledek" aria-label="Permalink to &quot;Výsledek&quot;">​</a></h2><p>Po dokončení musí být možné nainstalovat vygenerované APK, aplikace se bez chyb spustí a načte reálná data z backendu.</p>',11)])])}const v=a(i,[["render",n]]);export{m as __pageData,v as default};
